const outputItems = $input.first().json.output;
const message = outputItems.find(item => item.content && item.content.length > 0);
const texts = message.content.map(item => {
  let text = item.text;
  try {
    const parsed = JSON.parse(text);
    const firstString = Object.values(parsed).find(v => typeof v === 'string');
    if (firstString) text = firstString;
  } catch (e) {
    const match = text.match(/"\w+"\s*:\s*"([\s\S]*)/);
    if (match) text = match[1].replace(/"\s*\}?\s*$/, '').replace(/\\n/g, '\n');
  }
  return text;
});
return [{ json: { output: texts.join('\n') } }];
